// Segment Transcript
// -------------------------------------------------------------
// Agrupa las palabras devueltas por Whisper en "chunks" de 3-7s
// respetando finales de frase (puntos, comas largas).
//
// Output: UN solo item con `segments: Array<{start, end, text}>`,
// y se reanuda el binario `audio` del Webhook para los nodos siguientes.
// -------------------------------------------------------------

const transcript = $input.first().json;
const words = transcript.words || [];

const MIN_DUR = 3.0;
const MAX_DUR = 7.0;
const TARGET_DUR = 5.0;

let segments = [];

if (words.length === 0) {
  // Whisper no devolvio palabras (configuracion antigua del modelo, etc).
  // Fallback: un unico segmento con el texto completo.
  const total = transcript.duration || transcript.segments?.[transcript.segments.length-1]?.end || 0;
  if (transcript.text && total > 0) {
    segments = [{ start: 0, end: total, text: transcript.text.trim() }];
  } else {
    throw new Error('Whisper devolvio una respuesta vacia o sin timing.');
  }
} else {
  let cur = { start: words[0].start, words: [] };
  for (let i = 0; i < words.length; i++) {
    const w = words[i];
    cur.words.push(w);
    const dur = w.end - cur.start;
    const wordTxt = String(w.word || '').trim();
    const endsWithPunct = /[.!?]$/.test(wordTxt) || (dur >= TARGET_DUR && /,$/.test(wordTxt));
    const isLast = i === words.length - 1;

    if (isLast || dur >= MAX_DUR || (dur >= MIN_DUR && endsWithPunct)) {
      segments.push({
        start: cur.start,
        end: w.end,
        text: cur.words.map(x => String(x.word || '').trim()).join(' ').replace(/\s+/g, ' ').trim()
      });
      if (!isLast) {
        cur = { start: words[i+1].start, words: [] };
      }
    }
  }
}

// Devolvemos UN item con todo el array ("Once for all items" pattern)
// y reanudamos el binario `audio` del Webhook para que llegue al worker.
return [{
  json: {
    segments,
    duration: transcript.duration ?? null,
    full_text: transcript.text ?? ''
  },
  binary: $('Webhook').first().binary
}];

