parameters.jsCode:
// Merge Plan
// -------------------------------------------------------------
// Combina los segmentos de Whisper (texto + timing) con el plan visual
// de Llama (keywords_en + asset_type_preference + medical_concept).
//
// El binario `audio` se reanuda del Webhook para llegar al worker mas tarde.
// -------------------------------------------------------------

const segments = $('Segment Transcript').first().json.segments;
const groqResponse = $input.first().json;
const content = groqResponse.choices?.[0]?.message?.content;
if (!content) {
  throw new Error('Visual Planner: Groq no devolvio contenido. Respuesta: ' + JSON.stringify(groqResponse).slice(0, 400));
}

let parsed;
try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  throw new Error('Visual Planner: JSON invalido. content=' + String(content).slice(0, 400));
}

const plan = parsed.plan;
if (!Array.isArray(plan) || plan.length !== segments.length) {
  throw new Error(`Visual Planner: longitud del plan (${plan?.length}) != segmentos (${segments.length})`);
}

const merged = segments.map((s, i) => ({
  start: s.start,
  end: s.end,
  text: s.text,
  keywords_en: String(plan[i].keywords_en || 'medical anatomy').toLowerCase(),
  asset_type_preference: plan[i].asset_type_preference || 'either',
  medical_concept: plan[i].medical_concept || ''
}));

return [{
  json: {
    segments: merged,
    session_id: $('Initialize Session').first().json.session_id,
    topic: $('Initialize Session').first().json.topic,
    style: $('Initialize Session').first().json.style,
    duration: $('Segment Transcript').first().json.duration
  },
  binary: $('Webhook').first().binary
}];

// Search & Pick Assets
// -------------------------------------------------------------
// Para cada segmento:
//   1) Pexels: 1 busqueda de imagenes + 1 de videos (vertical).
//   2) Pixabay como fallback si Pexels devuelve <3 candidatos.
//   3) Filtra los assets bloqueados (lista de Get Blocked Assets) y los
//      ya elegidos en este mismo reel.
//   4) Elige el primer candidato disponible.
//
// Sale: 1 item con segments enriquecidos con `asset = {type, url, source, asset_id}`.
// -------------------------------------------------------------

const data = $('Merge Plan').first().json;
const segs = data.segments;
const blockedRows = $items('Get Blocked Assets') || [];
const blockedSet = new Set(blockedRows.map(r => `${r.json.source}:${r.json.asset_id}`));

const PEXELS_KEY = $env.PEXELS_API_KEY;
const PIXABAY_KEY = $env.PIXABAY_API_KEY;
if (!PEXELS_KEY) throw new Error('PEXELS_API_KEY no esta definida en el entorno de n8n');

async function pexelsImages(query) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.pexels.com/v1/search?query=${encodeURIComponent(query)}&orientation=portrait&per_page=15`,
      headers: { Authorization: PEXELS_KEY },
      json: true
    });
    return (res.photos || []).map(p => ({
      type: 'image',
      source: 'pexels',
      asset_id: String(p.id),
      url: p.src?.large2x || p.src?.large || p.src?.original
    })).filter(c => c.url);
  } catch (e) { return []; }
}

async function pexelsVideos(query) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.pexels.com/videos/search?query=${encodeURIComponent(query)}&orientation=portrait&per_page=15`,
      headers: { Authorization: PEXELS_KEY },
      json: true
    });
    return (res.videos || []).map(v => {
      const file = (v.video_files || []).find(f => f.quality === 'hd') ||
                   (v.video_files || []).find(f => f.quality === 'sd') ||
                   (v.video_files || [])[0];
      return file ? {
        type: 'video',
        source: 'pexels',
        asset_id: String(v.id),
        url: file.link
      } : null;
    }).filter(Boolean);
  } catch (e) { return []; }
}

async function pixabayImages(query) {
  if (!PIXABAY_KEY) return [];
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://pixabay.com/api/?key=${PIXABAY_KEY}&q=${encodeURIComponent(query)}&orientation=vertical&per_page=15&safesearch=true`,
      json: true
    });
    return (res.hits || []).map(p => ({
      type: 'image',
      source: 'pixabay',
      asset_id: String(p.id),
      url: p.largeImageURL || p.webformatURL
    })).filter(c => c.url);
  } catch (e) { return []; }
}

const pickedKeys = new Set();
const enriched = [];

for (let i = 0; i < segs.length; i++) {
  const s = segs[i];
  const q = s.keywords_en || s.medical_concept || 'medical anatomy';
  const wantVideo = s.asset_type_preference === 'video';
  const wantImage = s.asset_type_preference === 'image';

  let candidates = [];
  if (wantVideo) {
    candidates = candidates.concat(await pexelsVideos.call(this, q));
    candidates = candidates.concat(await pexelsImages.call(this, q));
  } else if (wantImage) {
    candidates = candidates.concat(await pexelsImages.call(this, q));
  } else {
    candidates = candidates.concat(await pexelsImages.call(this, q));
    candidates = candidates.concat(await pexelsVideos.call(this, q));
  }

  if (candidates.length < 3) {
    candidates = candidates.concat(await pixabayImages.call(this, q));
  }

  const winner = candidates.find(c =>
    !blockedSet.has(`${c.source}:${c.asset_id}`) &&
    !pickedKeys.has(`${c.source}:${c.asset_id}`)
  );

  if (!winner) {
    throw new Error(`Sin assets disponibles para el segmento ${i} ("${s.medical_concept || s.keywords_en}"). ` +
                    `Probados ${candidates.length} candidatos, todos ya usados.`);
  }

  pickedKeys.add(`${winner.source}:${winner.asset_id}`);
  enriched.push({
    start: s.start,
    end: s.end,
    subtitle_text: s.text,
    asset: {
      type: winner.type,
      url: winner.url,
      source: winner.source,
      asset_id: winner.asset_id
    }
  });
}

return [{
  json: {
    segments: enriched,
    session_id: data.session_id,
    topic: data.topic,
    style: data.style,
    duration: data.duration
  },
  binary: $('Webhook').first().binary
}];

// Build Compose Spec
// -------------------------------------------------------------
// Construye el JSON spec que se enviara al worker FFmpeg en el campo
// `spec` del multipart. El audio va por separado como fichero binario
// (campo `audio`), por lo que `audio_url` es solo informativo.
// -------------------------------------------------------------

const data = $('Search & Pick Assets').first().json;
const topic = (data.topic || '').trim();

const spec = {
  audio_url: 'inline://multipart-audio',
  duration: data.duration,
  segments: data.segments,
  title_badge: topic
    ? { show: true, text: topic.toUpperCase().slice(0, 60), duration: 2.0 }
    : { show: false },
  signature: '@draydeliserodriguez',
  output_format: 'mp4'
};

return [{
  json: {
    spec,
    session_id: data.session_id
  },
  binary: $('Webhook').first().binary
}];

